// Replace with SQL nodes for rent_payments, maintenance_tickets, and units.
const summary = {
  landlordId: '00000000-0000-0000-0000-000000000001',
  period: 'previous_month',
  rentCollected: 12450,
  maintenanceCost: 1430,
  occupancyRate: 0.92,
  overdueRent: 850
};

summary.noi = summary.rentCollected - summary.maintenanceCost;
summary.alerts = [];

if (summary.occupancyRate < 0.9) summary.alerts.push('occupancy-risk');
if (summary.maintenanceCost > summary.rentCollected * 0.2) summary.alerts.push('maintenance-cost-spike');

return [{ json: summary }];

const data = $json;

const executiveSummary = `Collected $${data.rentCollected} in rent with NOI of $${data.noi}. Occupancy rate was ${(data.occupancyRate * 100).toFixed(1)}%.`;

return [{
  json: {
    ...data,
    executiveSummary,
    reportUrl: `https://example-r2.invalid/reports/${new Date().toISOString().slice(0, 10)}.pdf`
  }
}];

const runStamp = $now.toISO();

return [{
  json: {
    workflowName: 'monthly-reports',
    trigger: 'cron',
    outcome: 'success',
    landlordId: $json.landlordId,
    correlationId: $execution.id,
    idempotencyKey: `monthly-reports:${runStamp}:${$execution.id}`,
    details: {
      reportUrl: $json.reportUrl,
      rentCollected: $json.rentCollected,
      maintenanceCost: $json.maintenanceCost,
      occupancyRate: $json.occupancyRate,
      alerts: $json.alerts,
      runAt: runStamp
    }
  }
}];
